module float_multi (
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output reg [31:0] z
);

reg [2:0] counter;
reg [23:0] a_mantissa, b_mantissa, z_mantissa;
reg [9:0] a_exponent, b_exponent, z_exponent;
reg a_sign, b_sign, z_sign;
reg [49:0] product;
reg guard_bit, round_bit, sticky;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        counter <= 0;
        a_mantissa <= 0;
        b_mantissa <= 0;
        z_mantissa <= 0;
        a_exponent <= 0;
        b_exponent <= 0;
        z_exponent <= 0;
        a_sign <= 0;
        b_sign <= 0;
        z_sign <= 0;
        product <= 0;
        guard_bit <= 0;
        round_bit <= 0;
        sticky <= 0;
    end else begin
        case (counter)
            0: begin 
                a_mantissa <= a[22:0];
                b_mantissa <= b[22:0];
                a_exponent <= a[30:23];
                b_exponent <= b[30:23];
                a_sign <= a[31];
                b_sign <= b[31];
            end
            1: begin 
                if ((a == 32'b11111111111111111111111111111111) || (b == 32'b11111111111111111111111111111111)) begin
                    z <= 32'b11111111111111111111111111111111; 
                end else if ((a == 32'b01111111111111111111111111111111) && (b == 32'b01111111111111111111111111111111)) begin
                    z <= 32'b01111111111111111111111111111111; 
                end else begin
                    counter <= 2;
                end
            end
            2: begin 
                if (a_mantissa[23]) begin
                    a_mantissa <= {a_mantissa[22:0], 1'b0};
                    a_exponent <= a_exponent + 1;
                end
                if (b_mantissa[23]) begin
                    b_mantissa <= {b_mantissa[22:0], 1'b0};
                    b_exponent <= b_exponent + 1;
                end
                counter <= 3;
            end
            3: begin 
                product <= a_mantissa * b_mantissa;
                z_sign <= a_sign ^ b_sign;
                z_exponent <= a_exponent + b_exponent - 127;
                counter <= 4;
            end
            4: begin 
                guard_bit <= product[48];
                round_bit <= product[47];
                sticky <= product[46] | product[45] | product[44];
                if (round_bit & (sticky | guard_bit)) begin
                    product <= product + 1;
                end
                z_mantissa <= product[48:25];
                if (z_mantissa[24]) begin
                    z_mantissa <= {z_mantissa[23:0], 1'b0};
                    z_exponent <= z_exponent + 1;
                end
                counter <= 5;
            end
            5: begin 
                z <= {z_sign, z_exponent, z_mantissa};
                counter <= 0;
            end
        endcase
    end
end

endmodule
